#include <iostream>
using namespace std;

int main() {
    int x = 42;
    int* p = &x;  // p points to x

    cout << x    << endl;  // value of x
    cout << &x   << endl;  // address of x (hex)
    cout << p    << endl;  // same address
    cout << *p   << endl;  // value AT that address: 42

    *p = 99;               // change x through pointer
    cout << x    << endl;  // x is now 99!

    return 0;
}

#include <iostream>
using namespace std;

void printIfValid(int* p) {
    if (p != nullptr) {
        cout << "Value: " << *p << endl;
    } else {
        cout << "Null pointer!" << endl;
    }
}

int main() {
    int x = 42;
    int* p = &x;
    int* q = nullptr;

    printIfValid(p);
    printIfValid(q);

    // Never do this:
    // cout << *q << endl;  // undefined behaviour — likely crash!

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int arr[] = {10, 20, 30, 40, 50};
    int* p = arr;  // points to first element

    cout << *p       << endl;  // 10
    cout << *(p + 1) << endl;  // 20
    cout << *(p + 4) << endl;  // 50

    // Iterate using pointer arithmetic:
    int* end = arr + 5;  // past the last element
    for (int* it = arr; it != end; ++it) {
        cout << *it << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int a = 10, b = 20;

    // Pointer to const: can't modify value through pointer
    const int* p = &a;
    cout << *p << endl;
    p = &b;        // OK: can change where it points
    cout << *p << endl;
    // *p = 99;    // ERROR: can't modify through const pointer

    // Const pointer: can't change where it points
    int* const q = &a;
    *q = 99;       // OK: can modify value
    cout << a << endl;
    // q = &b;    // ERROR: can't reassign const pointer

    return 0;
}

#include <iostream>
using namespace std;

void withPointer(int* p) {
    if (p) *p *= 2;
}

void withReference(int& r) {
    r *= 2;  // no null check needed — references can't be null
}

int main() {
    int x = 10;
    withPointer(&x);
    cout << x << endl;   // 20

    withReference(x);
    cout << x << endl;   // 40

    // Reference as alias:
    int& ref = x;
    ref = 100;
    cout << x << endl;   // 100 — same variable!

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

void printReverse(const int* arr, int size) {
    for (int i = size - 1; i >= 0; i--) {
        cout << arr[i] << " ";
    }
    cout << endl;
}

int main() {
    int numbers[] = {1, 2, 3, 4, 5};
    printReverse(numbers, 5);  // array decays to pointer

    // Pointer to string:
    const char* cstr = "Hello, C++!";  // C-string literal
    cout << cstr << endl;              // cout prints until '\0'
    cout << *cstr << endl;             // first char: 'H'
    cout << cstr + 7 << endl;          // pointer + 7 = 'C++!'

    return 0;
}
